const DEFAULT_ORIGIN = process.env.APP_URL || "http://localhost:3000";
const stripeSecret = process.env.STRIPE_SECRET_KEY || "";
const stripe = stripeSecret
  ? new Stripe(stripeSecret, { apiVersion: "2023-10-16" as any })
  : null;

