52	async function fetchWithTimeout(url: string, opts: RequestInit = {}): Promise<Response> {
53	  let lastErr: unknown;
54	  for (let i = 0; i < CONFIG.retryAttempts; i++) {
55	    try {
56	      const r = await fetch(url, { ...opts, signal: AbortSignal.timeout(CONFIG.fetchTimeoutMs) });
57	      if (r.status === 429) {
58	        const retryAfter = Number(r.headers.get('Retry-After') ?? (i + 1) * 2);
59	        await new Promise(res => setTimeout(res, retryAfter * 1000));
60	        continue;
61	      }
62	      return r;
63	    } catch (e) {
64	      lastErr = e;
65	      if (i < CONFIG.retryAttempts - 1) await new Promise(res => setTimeout(res, 500 * (i + 1)));
66	    }
