296	  console.error(`[CF]  ${CF_OCDS_BASE} → fetched=${cf.stats.fetched} passed=${cf.stats.passed} failed=${cf.stats.failed}${cf.stats.error ? ' ERR=' + cf.stats.error : ''}`);
